def gen(rng, size):
    n = max(1, size)
    x = rng.randrange(1, 10001)
    y = rng.randrange(1, 10001)
    pts = []
    for _ in range(n):
        r = rng.random()
        if r < 0.3:
            pts.append([x, rng.randrange(1, 10001)])
        elif r < 0.6:
            pts.append([rng.randrange(1, 10001), y])
        else:
            pts.append([rng.randrange(1, 10001), rng.randrange(1, 10001)])
    return [x, y, pts]

