class Solution:
    def nearestValidPoint(self, x, y, points):
        best = -1
        bestd = None
        for i, (a, b) in enumerate(points):
            if a == x or b == y:
                d = abs(a - x) + abs(b - y)
                if bestd is None or d < bestd:
                    bestd = d
                    best = i
        return best

