solutions.javascript:
var nearestValidPoint = function(x, y, points) {
    let best = -1, bestd = Infinity;
    for (let i = 0; i < points.length; i++) {
        const [a, b] = points[i];
        if (a === x || b === y) {
            const d = Math.abs(a - x) + Math.abs(b - y);
            if (d < bestd) { bestd = d; best = i; }
        }
    }
    return best;
};
